<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Bouncing Ball Physics Playground</title>
    <style>
        * {
            margin: 0;
            padding: 0;
            box-sizing: border-box;
        }

        body {
            background: #1a1a2e;
            display: flex;
            justify-content: center;
            align-items: center;
            min-height: 100vh;
            font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
            margin: 0;
            padding: 20px;
        }

        .container {
            background: #16213e;
            padding: 30px;
            border-radius: 16px;
            box-shadow: 0 20px 40px rgba(0, 0, 0, 0.5);
            display: flex;
            flex-direction: column;
            align-items: center;
            gap: 20px;
        }

        canvas {
            display: block;
            width: 500px;
            height: 500px;
            background: #0f0f1a;
            border-radius: 12px;
            box-shadow: inset 0 0 30px rgba(0, 0, 0, 0.7), 0 10px 20px rgba(0, 0, 0, 0.3);
            cursor: crosshair;
            border: 2px solid #2a2a4a;
        }

        .controls {
            display: flex;
            gap: 15px;
            flex-wrap: wrap;
            justify-content: center;
        }

        button {
            padding: 12px 28px;
            font-size: 16px;
            font-weight: bold;
            border: none;
            border-radius: 30px;
            cursor: pointer;
            transition: all 0.2s ease;
            letter-spacing: 0.5px;
            background: #2d2d5e;
            color: #e0e0ff;
            box-shadow: 0 4px 10px rgba(0, 0, 0, 0.3);
            text-transform: uppercase;
        }

        button:hover {
            transform: translateY(-2px);
            box-shadow: 0 8px 20px rgba(0, 0, 0, 0.4);
            background: #3d3d7e;
        }

        button:active {
            transform: translateY(1px);
            box-shadow: 0 2px 5px rgba(0, 0, 0, 0.3);
        }

        #drop {
            background: #e94560;
            color: white;
        }

        #drop:hover {
            background: #ff6b81;
        }

        #play {
            background: #0f3460;
            color: white;
        }

        #play:hover {
            background: #1a4a8a;
        }

        #clear {
            background: #533a5e;
            color: white;
        }

        #clear:hover {
            background: #6e4d7c;
        }
    </style>
</head>
<body>
    <div class="container">
        <canvas id="sim" width="500" height="500"></canvas>
        <div class="controls">
            <button id="drop">Drop Ball</button>
            <button id="play">Pause</button>
            <button id="clear">Clear</button>
        </div>
    </div>

    <script>
        (function() {
            const canvas = document.getElementById('sim');
            const ctx = canvas.getContext('2d');

            // Canvas logical size (same as CSS dimensions)
            const W = 500;
            const H = 500;
            canvas.width = W;
            canvas.height = H;

            // Simulation state
            let balls = [];
            let animationId = null;
            let running = true;

            // Physics constants
            const GRAVITY = 0.5;
            const RESTITUTION = 0.8;
            const DEFAULT_RADIUS = 15;

            // Exposed API
            window.sim = {
                w: W,
                h: H,
                balls: () => balls.map(b => ({ ...b })),
                addBall: (x, y, vx = 0, vy = 0, r = null) => {
                    const radius = r !== null ? r : DEFAULT_RADIUS;
                    // Clamp position so ball is fully inside canvas
                    const clampedX = Math.min(Math.max(x, radius), W - radius);
                    const clampedY = Math.min(Math.max(y, radius), H - radius);
                    balls.push({
                        x: clampedX,
                        y: clampedY,
                        vx: vx,
                        vy: vy,
                        r: radius
                    });
                    draw();
                },
                clear: () => {
                    balls = [];
                    draw();
                },
                step: (dt = 1) => {
                    update(dt);
                    draw();
                }
            };

            // Drop button: add ball at top center with slight random horizontal velocity
            function dropBall() {
                const x = W / 2 + (Math.random() - 0.5) * 60;
                const y = 40;
                const vx = (Math.random() - 0.5) * 4;
                const vy = Math.random() * 2;
                window.sim.addBall(x, y, vx, vy, DEFAULT_RADIUS);
            }

            // Toggle animation
            function togglePlay() {
                running = !running;
                const playBtn = document.getElementById('play');
                playBtn.textContent = running ? 'Pause' : 'Play';
                if (running) {
                    animate();
                } else {
                    if (animationId) {
                        cancelAnimationFrame(animationId);
                        animationId = null;
                    }
                }
            }

            // Clear all balls
            function clearBalls() {
                window.sim.clear();
            }

            // Canvas click handler
            canvas.addEventListener('click', (e) => {
                const rect = canvas.getBoundingClientRect();
                const scaleX = W / rect.width;   // canvas logical pixels per CSS pixel
                const scaleY = H / rect.height;
                const mouseX = (e.clientX - rect.left) * scaleX;
                const mouseY = (e.clientY - rect.top) * scaleY;

                // Random small velocity for interaction fun
                const vx = (Math.random() - 0.5) * 3;
                const vy = (Math.random() - 0.5) * 3;
                window.sim.addBall(mouseX, mouseY, vx, vy, DEFAULT_RADIUS);
            });

            // Physics update
            function update(dt = 1) {
                for (let ball of balls) {
                    // Apply gravity
                    ball.vy += GRAVITY * dt;

                    // Update position
                    ball.x += ball.vx * dt;
                    ball.y += ball.vy * dt;

                    // Collision with edges (bounce with energy loss)
                    // Left edge
                    if (ball.x - ball.r < 0) {
                        ball.x = ball.r;
                        ball.vx = -ball.vx * RESTITUTION;
                    }
                    // Right edge
                    if (ball.x + ball.r > W) {
                        ball.x = W - ball.r;
                        ball.vx = -ball.vx * RESTITUTION;
                    }
                    // Top edge
                    if (ball.y - ball.r < 0) {
                        ball.y = ball.r;
                        ball.vy = -ball.vy * RESTITUTION;
                    }
                    // Bottom edge
                    if (ball.y + ball.r > H) {
                        ball.y = H - ball.r;
                        ball.vy = -ball.vy * RESTITUTION;
                    }

                    // Safety: ensure ball stays within bounds (prevents tunneling)
                    ball.x = Math.min(Math.max(ball.x, ball.r), W - ball.r);
                    ball.y = Math.min(Math.max(ball.y, ball.r), H - ball.r);
                }
            }

            // Drawing
            function draw() {
                ctx.clearRect(0, 0, W, H);

                // Draw subtle grid for visual depth
                ctx.strokeStyle = '#1a1a2e';
                ctx.lineWidth = 0.5;
                for (let i = 0; i < W; i += 40) {
                    ctx.beginPath();
                    ctx.moveTo(i, 0);
                    ctx.lineTo(i, H);
                    ctx.stroke();
                }
                for (let i = 0; i < H; i += 40) {
                    ctx.beginPath();
                    ctx.moveTo(0, i);
                    ctx.lineTo(W, i);
                    ctx.stroke();
                }

                // Draw balls
                for (let ball of balls) {
                    // Glow effect
                    ctx.shadowColor = '#e94560';
                    ctx.shadowBlur = 12;

                    // Gradient fill
                    const gradient = ctx.createRadialGradient(
                        ball.x - ball.r * 0.3, ball.y - ball.r * 0.3, ball.r * 0.1,
                        ball.x, ball.y, ball.r
                    );
                    gradient.addColorStop(0, '#ff6b81');
                    gradient.addColorStop(0.7, '#e94560');
                    gradient.addColorStop(1, '#a61e3a');

                    ctx.beginPath();
                    ctx.arc(ball.x, ball.y, ball.r, 0, Math.PI * 2);
                    ctx.fillStyle = gradient;
                    ctx.fill();

                    // Reset shadow for stroke
                    ctx.shadowBlur = 0;
                    ctx.strokeStyle = '#ffccd5';
                    ctx.lineWidth = 2;
                    ctx.stroke();

                    // Highlight
                    ctx.beginPath();
                    ctx.arc(ball.x - ball.r * 0.25, ball.y - ball.r * 0.25, ball.r * 0.25, 0, Math.PI * 2);
                    ctx.fillStyle = 'rgba(255, 255, 255, 0.5)';
                    ctx.fill();
                }

                // Reset shadow
                ctx.shadowBlur = 0;
            }

            // Animation loop
            function animate() {
                if (!running) return;
                update(1);
                draw();
                animationId = requestAnimationFrame(animate);
            }

            // Event listeners
            document.getElementById('drop').addEventListener('click', dropBall);
            document.getElementById('play').addEventListener('click', togglePlay);
            document.getElementById('clear').addEventListener('click', clearBalls);

            // Initial setup: drop a couple of balls for immediate satisfaction
            window.sim.addBall(150, 100, 2, 0, 18);
            window.sim.addBall(350, 150, -1.5, 1, 14);
            window.sim.addBall(250, 200, 0.5, -2, 20);

            // Start animation
            animate();

            // Ensure play button shows correct state
            document.getElementById('play').textContent = 'Pause';
        })();
    </script>
</body>
</html>
